  1→import './editor.css';
  2→import { motion, AnimatePresence } from "framer-motion";
  3→import React, { useCallback, useEffect, useState, useRef } from 'react';
  4→import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
  5→import EditorInner from './RichTextEditor.jsx';
  6→import ToolBar from './Toolbar';
  7→import { $getRoot } from 'lexical';
  8→import { deleteJournalImage, saveDraft } from '../../../../API/Api.js';
  9→import { useAuth } from '../../../Context/useAuth.js';
 10→import { useQueryClient } from '@tanstack/react-query';
 11→
 12→class ErrorBoundary extends React.Component {
 13→  state = { error: null };
 14→  static getDerivedStateFromError(error) {
 15→    return { error };
 16→  }
 17→  render() {
 18→    if (this.state.error) {
 19→      return <div>Error: {this.state.error.message}</div>;
 20→    }
 21→    return this.props.children;
 22→  }
 23→}
 24→
 25→const Editor=({onClose, initialTitle = '', promptId = null, promptText = null, draftId = null, draftContent = null}) =>{
 26→    const {session} = useAuth();
 27→    const queryClient = useQueryClient();
 28→
 29→    const [title, setTitle] = useState(initialTitle || '')
 30→    const [wordCount, setWordCount] = useState(0);
 31→    const [editor] = useLexicalComposerContext();
 32→    const currentDraftIdRef = useRef(draftId);
 33→    const editorStateRef = useRef({ hasChanges: false, hasContent: false, editorState: null, title: '' });
 34→    const [showCloseConfirm, setShowCloseConfirm] = useState(false);
 35→    const [isSavingDraft, setIsSavingDraft] = useState(false);
 36→    const [saveError, setSaveError] = useState(false);
 37→    const saveButtonRef = useRef(null);
 38→    const isClosingRef = useRef(false);
 39→
 40→    const [uploadedImagePaths, setUploadedImagePaths] = useState([]);
 41→
 42→    const addUploadedImagePath = useCallback((imagePath) =>{
 43→      setUploadedImagePaths((prev) => [...prev, imagePath]);
 44→    }, [])
 45→
 46→    useEffect(() => {
 47→        setTitle(initialTitle || '');
 48→    }, [initialTitle]);
 49→
 50→    // Load draft content into Lexical editor on mount
 51→    useEffect(() => {
 52→        if (draftContent && editor) {
 53→            try {
 54→                const parsedState = editor.parseEditorState(draftContent);
 55→                editor.setEditorState(parsedState);
 56→            } catch (err) {
 57→                console.error('Failed to load draft content:', err);
 58→            }
 59→        }
 60→    }, [draftContent, editor]);
 61→
 62→    const handleDraftIdCreated = useCallback((newDraftId) => {
 63→        currentDraftIdRef.current = newDraftId;
 64→    }, []);
 65→
 66→    const handleCloseEditor = useCallback(async() => {
 67→      // Only delete uploaded images if there's no saved draft
 68→      // (drafts own their images)
 69→      if(uploadedImagePaths.length > 0 && !currentDraftIdRef.current){
 70→        const message = await deleteJournalImage(session?.access_token, uploadedImagePaths)
 71→        if(message){
 72→          // console.log(message.message)
 73→        }
 74→      }
 75→
 76→        editor.update(() => {
 77→            const root = $getRoot();
 78→            root.clear();
 79→            onClose();
 80→        })
 81→    }, [editor, onClose, session?.access_token, uploadedImagePaths])
 82→
 83→    const handleCloseEditorOnSave = useCallback(async() => {
 84→      editor.update(() => {
 85→            const root = $getRoot();
 86→            root.clear();
 87→            onClose();
 88→      })
 89→    }, [onClose, editor])
 90→
 91→    const handleCloseClick = useCallback(() => {
 92→        if (isClosingRef.current) return;
 93→        const { hasChanges, hasContent } = editorStateRef.current;
 94→        if (hasChanges && hasContent) {
 95→            setShowCloseConfirm(true);
 96→        } else {
 97→            isClosingRef.current = true;
 98→            handleCloseEditor();
 99→        }
100→    }, [handleCloseEditor])
101→
102→    const handleConfirmSaveDraft = useCallback(async () => {
103→        let currentEditorState;
104→        editor.read(() => {
105→            currentEditorState = JSON.stringify(editor.getEditorState().toJSON());
106→        });
107→        if (!currentEditorState || !session?.access_token) {
108→            handleCloseEditor();
109→            return;
110→        }
111→        setSaveError(false);
112→        setIsSavingDraft(true);
113→
114→        // Cancel pending auto-save timer
115→        if (editorStateRef.current.saveTimerRef) {
116→            clearTimeout(editorStateRef.current.saveTimerRef.current);
117→        }
118→
119→        try {
120→            await saveDraft(session.access_token, {
121→                content: currentEditorState,
122→                title: title || '',
123→                draftId: currentDraftIdRef.current || null,
124→                prompt_id: promptId || null,
125→            });
126→            queryClient.invalidateQueries({ queryKey: ['journal-drafts'], refetchType: 'active' });
127→            handleCloseEditorOnSave();
128→        } catch (err) {
129→            console.error('Failed to save draft on close:', err);
130→            setSaveError(true);
131→            setIsSavingDraft(false);
132→        }
133→    }, [editor, session?.access_token, title, promptId, queryClient, handleCloseEditor, handleCloseEditorOnSave])
134→
135→    const handleConfirmDiscard = useCallback(() => {
136→        setShowCloseConfirm(false);
137→        handleCloseEditor();
138→    }, [handleCloseEditor])
139→
140→    // Escape key dismisses dialog
141→    useEffect(() => {
142→        if (!showCloseConfirm) return;
143→        const handleKeyDown = (e) => {
144→            if (e.key === 'Escape') handleConfirmDiscard();
145→        };
146→        document.addEventListener('keydown', handleKeyDown);
147→        return () => document.removeEventListener('keydown', handleKeyDown);
148→    }, [showCloseConfirm, handleConfirmDiscard]);
149→
150→    // Auto-focus Save Draft button when dialog opens
151→    useEffect(() => {
152→        if (showCloseConfirm) saveButtonRef.current?.focus();
153→    }, [showCloseConfirm]);
154→
155→    return(
156→        <>
157→        <div className='editor-parent-container'>
158→
159→            <motion.div
160→            initial={{scale: 0, opacity: 0.8}}
161→            animate={{scale: 1, opacity: 1}}
162→            exit={{scale: 0.8, opacity: 0,}}
163→            transition={{type: 'spring', stiffness: 260, damping: 25}}
164→            className="editor-container"
165→            >
166→                <div className='editor-close-bttn-container'>
167→                    <button
168→                        onClick={handleCloseClick}
169→                        className='editor-close-bttn'
170→                        aria-label="Close editor"
171→                        title="Close"
172→                    >
173→                        <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="m256-200-56-56 224-224-224-224 56-56 224 224 224-224 56 56-224 224 224 224-56 56-224-224-224 224Z"/></svg>
174→                    </button>
175→                </div>
176→
177→                <input value={title} onChange={(e) => setTitle(e.target.value)} className='content-title-input' type="text" placeholder='Title' />
178→
179→                <div className="toolbar-wrapper">
180→                    <ToolBar addUploadedImagePath={addUploadedImagePath}/>
181→                </div>
182→
183→                <div className="editor-mode-shell">
184→                    <ErrorBoundary>
185→                        <EditorInner
186→                            addUploadImagesPath={addUploadedImagePath}
187→                            onclose={handleCloseEditor}
188→                            onCloseOnSave={handleCloseEditorOnSave}
189→                            title={title}
190→                            setWordCount={setWordCount}
191→                            wordCount={wordCount}
192→                            promptId={promptId}
193→                            draftId={draftId}
194→                            onDraftIdCreated={handleDraftIdCreated}
195→                            editorStateRef={editorStateRef}
196→                        />
197→                    </ErrorBoundary>
198→                </div>
199→                <AnimatePresence>
200→                    {showCloseConfirm && (
201→                        <motion.div
202→                            className="editor-close-confirm-overlay"
203→                            initial={{ opacity: 0 }}
204→                            animate={{ opacity: 1 }}
205→                            exit={{ opacity: 0 }}
206→                            transition={{ duration: 0.15 }}
207→                            onClick={handleConfirmDiscard}
208→                        >
209→                            <motion.div
210→                                className="editor-close-confirm-card"
211→                                initial={{ scale: 0.9, opacity: 0 }}
212→                                animate={{ scale: 1, opacity: 1 }}
213→                                exit={{ scale: 0.9, opacity: 0 }}
214→                                transition={{ type: 'spring', stiffness: 300, damping: 25 }}
215→                                onClick={(e) => e.stopPropagation()}
216→                            >
217→                                <p className="editor-close-confirm-message">
218→                                    {currentDraftIdRef.current ? 'Save changes before closing?' : 'Save as draft before closing?'}
219→                                </p>
220→                                {saveError && (
221→                                    <p className="editor-close-confirm-error">Couldn't save. Try again?</p>
222→                                )}
223→                                <div className="editor-close-confirm-actions">
224→                                    <button
225→                                        className="editor-close-confirm-discard"
226→                                        onClick={handleConfirmDiscard}
227→                                        disabled={isSavingDraft}
228→                                    >
229→                                        Discard
230→                                    </button>
231→                                    <button
232→                                        ref={saveButtonRef}
233→                                        className="editor-close-confirm-save"
234→                                        onClick={handleConfirmSaveDraft}
235→                                        disabled={isSavingDraft}
236→                                    >
237→                                        {isSavingDraft ? 'Saving...' : 'Save Draft'}
238→                                    </button>
239→                                </div>
240→                            </motion.div>
241→                        </motion.div>
242→                    )}
243→                </AnimatePresence>
244→            </motion.div>
245→        </div>
246→        </>
247→    )
248→}
249→export default Editor;
