 3→function ImageComponent({ src, nodeKey }){
 4→  const [editor] = useLexicalComposerContext();
 5→  const handleDelete = (e) => {
 6→    e.stopPropagation();
 7→    editor.update(() => {
 8→      const node = editor.getEditorState()._nodeMap.get(nodeKey);
 9→      if (node) {
10→        try {
11→          node.remove();
12→        } catch (error) {
13→          console.error("Failed to remove image node:", error);
14→        }
15→      }
16→    });
17→  };
18→
19→  return (
20→    
21→    <div className="image-wrapper">
22→      <img src={src} alt="content image" className="content_images" loading="lazy" />
23→      <div className="image-delete" onClick={handleDelete}>
24→        <svg
25→          xmlns="http://www.w3.org/2000/svg"
26→          height="24px"
27→          viewBox="0 -960 960 960"
28→          width="24px"
29→          fill="#FFFFFF"
30→          aria-label="Delete image"
31→        >
32→          <path d="m256-200-56-56 224-224-224-224 56-56 224 224 224-224 56 56-224 224 224 224-56 56-224-224-224 224Z" />
33→        </svg>
34→      </div>
35→    </div>
36→  );
37→}
38→export default ImageComponent;

  1→import { useState, useRef, useEffect } from 'react';
  2→import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
  3→import { $getNodeByKey } from 'lexical';
  4→import { deleteJournalImage } from '../../../../API/Api';
  5→import { useAuth } from '../../../Context/useAuth';
