271→          <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="#FFFFFF"><path d="M482-160q-134 0-228-93t-94-227q0-134 94-228t228-94q62 0 118 23t98 65V-840h80v240H538v-80h128q-30-38-74.5-59T482-740q-100 0-170 70.5T242-480q0 100 70 170t170 70q77 0 139-44t87-116h84q-28 106-114 173t-196 67Z"/></svg>
272→        </div>
273→        <div onClick={(e) => handleDelete(e)} className='image-action-btn' title='Delete image'>
