 82→    const toCompactRgb = (value) => {
 83→        if (!value) return '';
 84→        return value.toLowerCase().replace(/\s+/g, '');
 85→    };
 86→
 87→    const normalizeColor = (value) => {
 88→        if (!value) return '';
 89→        const trimmed = value.trim().toLowerCase();
 90→        if (!trimmed.startsWith('#')) {
 91→            return toCompactRgb(trimmed);
 92→        }
 93→
 94→        let hex = trimmed.slice(1);
 95→        if (hex.length === 3) {
 96→            hex = hex.split('').map((char) => `${char}${char}`).join('');
 97→        }
 98→        if (hex.length !== 6) {
 99→            return trimmed;
100→        }
101→
102→        const r = parseInt(hex.slice(0, 2), 16);
103→        const g = parseInt(hex.slice(2, 4), 16);
104→        const b = parseInt(hex.slice(4, 6), 16);
105→
106→        return `rgb(${r},${g},${b})`;
107→    };
